mapper.select:
SELECT
-- 级联表的字段 ,cheliang.shangjia_id as cheliangShangjiaId ,cheliang.cheliang_name as cheliangName ,cheliang.cheliang_photo as cheliangPhoto ,cheliang.cheliang_types as cheliangTypes ,cheliang.cheliang_new_money as cheliangNewMoney ,cheliang.shangxia_types as shangxiaTypes ,yonghu.yonghu_name as yonghuName ,yonghu.yonghu_phone as yonghuPhone ,yonghu.yonghu_id_number as yonghuIdNumber ,yonghu.yonghu_photo as yonghuPhoto ,yonghu.yonghu_email as yonghuEmail ,shangjia.shangjia_name as shangjiaName ,shangjia.shangjia_phone as shangjiaPhone ,shangjia.shangjia_email as shangjiaEmail
FROM cheliang_order a left JOIN cheliang cheliang ON a.cheliang_id = cheliang.id left JOIN yonghu yonghu ON a.yonghu_id = yonghu.id left JOIN shangjia shangjia ON a.shangjia_id = shangjia.id
and a.id in
#{item}
and a.cheliang_id = #{params.cheliangId}
and a.yonghu_id = #{params.yonghuId}
and a.shangjia_id = #{params.shangjiaId}
and a.cheliang_order_uuid_number like CONCAT('%',#{params.cheliangOrderUuidNumber},'%')
and a.cheliang_order_status_types = #{params.cheliangOrderStatusTypes}
and a.cheliang_order_status_types >= #{params.cheliangOrderStatusTypesStart}
and a.cheliang_order_status_types <= #{params.cheliangOrderStatusTypesEnd}
and a.cheliang_order_price >= #{params.cheliangOrderPriceStart}
and a.cheliang_order_price <= #{params.cheliangOrderPriceEnd}
and UNIX_TIMESTAMP(a.insert_time) >= UNIX_TIMESTAMP(#{params.insertTimeStart})
and UNIX_TIMESTAMP(a.insert_time) <= UNIX_TIMESTAMP(#{params.insertTimeEnd})
and cheliang.cheliang_name like CONCAT('%',#{params.cheliangName},'%')
and cheliang.cheliang_types = #{params.cheliangTypes}
and cheliang.shangxia_types = #{params.shangxiaTypes}
and yonghu.yonghu_name like CONCAT('%',#{params.yonghuName},'%')
and yonghu.yonghu_phone like CONCAT('%',#{params.yonghuPhone},'%')
and shangjia.shangjia_name like CONCAT('%',#{params.shangjiaName},'%')
and shangjia.shangjia_phone like CONCAT('%',#{params.shangjiaPhone},'%')
order by a.${params.orderBy} desc
